# Example: output validation wrapper for agent tool calls
import json
from typing import TypeVar, Callable, Any
from pydantic import BaseModel, ValidationError

T = TypeVar('T', bound=BaseModel)

def validated_tool_call(
    tool_fn: Callable[..., str],
    response_model: type[T],
    *args,
    **kwargs,
) -> T:
    """
    Call an LLM-backed tool and validate the response against a Pydantic model.
    Raises ValueError if the model returns malformed output.
    """
    raw_output = tool_fn(*args, **kwargs)
    try:
        parsed = json.loads(raw_output)
    except json.JSONDecodeError as e:
        raise ValueError(
            f'Tool returned non-JSON output: {raw_output[:200]}'
        ) from e
    try:
        return response_model.model_validate(parsed)
    except ValidationError as e:
        raise ValueError(
            f'Tool output did not match expected schema: {e}'
        ) from e
